#include <iostream>
#include <string>
#include <map>

using namespace std;

class TrieNode {
public:
    string key;
    map<char, TrieNode*> children;

    TrieNode(string k) : key(k) {}

    int countNodes() {
        return 1 + countNodesRecursive(children);
    }

    bool contains(string word) {
        return containsRecursive(word, children);
    }

private:
    int countNodesRecursive(map<char, TrieNode*> children) {
        int count = 0;
        for (auto pair : children) {
            count += pair.second->countNodes();
        }
        return count;
    }

    bool containsRecursive(string word, map<char, TrieNode*> children) {
        if (word.empty()) {
            return true;
        }
        if (children.find(word[0]) == children.end()) {
            return false;
        }
        return children[word[0]]->contains(word.substr(1));
    }
};

class Trie {
public:
    TrieNode* root;

    Trie() : root(new TrieNode("")) {}

    void insert(string word) {
        insertHelper(root, word);
    }

    void deleteNode(string word) {
        deleteNodeHelper(root, word);
    }

    int countNodes() {
        return root->countNodes();
    }

private:
    void insertHelper(TrieNode* node, string word) {
        if (word.empty()) {
            return;
        }
        if (node->children.find(word[0]) == node->children.end()) {
            node->children[word[0]] = new TrieNode(word[0]);
        }
        insertHelper(node->children[word[0]], word.substr(1));
    }

    void deleteNodeHelper(TrieNode* node, string word) {
        if (word.empty()) {
            return;
        }
        if (node->children.find(word[0]) == node->children.end()) {
            return;
        }
        deleteNodeHelper(node->children[word[0]], word.substr(1));
        if (node->children[word[0]]->children.empty()) {
            delete node->children[word[0]];
        }
    }
};

int main() {
    int count;
    cin >> count;
    for (int i = 0; i < count; i++) {
        string word;
        cin >> word;
        Trie trie;
        trie.insert(word);
        cout << trie.countNodes() << endl;
    }

    return 0;
}
